    for _ in range(n):
        operation, value = map(int, input().split())
        queue = Solution().enqueue(queue, len(queue), operation, value)
    print(queue)

solutions.cpp:
#include <iostream>
using namespace std;
class Solution {
public:
    vector<int> enqueue(vector<int>& queue, int n, int operation, int value) {
        if (operation == 1) {
            queue.push_back(value);
        }
        return queue;
    }
};
int main() {
    int n;
    cin >> n;
    vector<int> queue;
    for (int i = 0; i < n; i++) {
        int operation, value;
        cin >> operation >> value;
        queue = Solution().enqueue(queue, queue.size(), operation, value);
    }
    for (auto x : queue) {
        cout << x << ' ';
    }
    cout << endl;
    return 0;
}
